module reset_controller(  
    input wire clk,  
    input wire reset,  
    input wire input_signal,  
    output reg output_signal  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            output_signal <= 1'b0;  
        else  
            output_signal <= input_signal;  
    end  
endmodule
